<template>
  <v-toolbar app height="72px" v-if="hostId">
    <!-- <img :src="require('../assets/img/logo.svg')" class="img-responsive" height="24"/> -->
    
    <v-btn fab dark color="green lighten-1" to="/">
      <v-icon x-large>home</v-icon>
    </v-btn>
    
    <v-spacer></v-spacer>
    <v-badge color="red" overlap bottom right>
      <span slot="badge" v-if="events.length > 0">{{events.length}}</span>
      <v-menu :nudge-width="100">
        <v-btn slot="activator" fab dark color="green lighten-1">
          <v-icon x-large>mail</v-icon>
        </v-btn>
        <v-list v-if="events.length > 0">
          <v-list-tile v-for="event in events">
            <v-list-tile-content>
              <v-layout row wrap>
              <v-flex xs6 sm6>
                <v-text-field
                  :value="event.bookingId"
                  label="Booking ID"
                  disabled
                ></v-text-field>
              </v-flex>
              <v-flex xs6 sm6>
                <v-text-field
                  :value="event.listingName"
                  label="Listing Name"
                  disabled
                ></v-text-field>
              </v-flex>
              </v-layout>
            </v-list-tile-content>
            <v-list-tile-action>
              <v-btn icon ripple @click="pickEvent(event)">
                <v-icon color="green lighten-1">info</v-icon>
              </v-btn>
            </v-list-tile-action>
          </v-list-tile>
        </v-list>
      </v-menu>
    </v-badge>


    <v-spacer></v-spacer>
    <v-btn fab dark color="green lighten-1" to="/about">
      <v-icon x-large>help_outline</v-icon>
    </v-btn>

    <v-spacer></v-spacer>
    <v-btn fab dark color="green lighten-1" @click.native="toggleFullScreen">
      <v-icon x-large>zoom_out_map</v-icon>
    </v-btn>

    <v-spacer></v-spacer>
    <v-menu :nudge-width="100">
      <v-btn slot="activator" fab dark color="green lighten-1">
        <v-icon x-large>language</v-icon>
      </v-btn>


      <v-list>
        <v-list-tile
          v-for="item in languages"
          :key="item"
          @click="switchLocale(item)"
        >
          <v-list-tile-title>{{ $t( "menu." + item) }}</v-list-tile-title>
          <flag :iso="item" />
        </v-list-tile>
      </v-list>
    </v-menu>

    <v-spacer></v-spacer>
    <v-btn fab dark color="green lighten-1" @click.native="logout">
      <v-icon x-large>exit_to_app</v-icon>
    </v-btn>
  </v-toolbar>
</template>

<script>
import Vue from 'vue'
import { mapGetters, mapState, mapActions } from 'vuex'
import FlagIcon from 'vue-flag-icon'
import * as utils from '@/utils'
import store from '@/store'

Vue.use(FlagIcon)

export default {
  name: 'Menu',
  data: () => ({
    languages: [
      'gb', 'hk', 'jp'
    ],
    dialog: false,
  }),
  created () {
  },
  mounted () {
  },
  computed: mapState({
    hostId: state => state.session.hostId,
    events: state => state.host.events
  }),
  methods: {
    pickEvent (event) {
      console.log('pickEvent', event)

      const reservationCode = event.reservationCode
      const identityId = event.identityId

      this.removeEvent(event)

      this.pickReservation({ 
        reservationCode: reservationCode, 
        identityId: identityId 
      })
    },
    switchLocale (item) {
      this.$i18n.locale = item
    },
    toggleFullScreen() {
      try {
        utils.ToggleFullScreen()  
      } 
      catch (e) {
        window.alert(e)
      }
      
    },
    ...mapActions({
      logout: 'session/logout',
      pickReservation: 'host/pickReservation',
      removeEvent: 'host/removeEvent',
    })
  },
}
</script>